SELECT COUNT(*) AS QUANTIDADE FROM LATTES_P_BANCA LPB JOIN SERVIDOR S ON S.PK_SIAPE = LPB.FK_SIAPE JOIN LATTES_BANCA LB ON LB.PK = LPB.FK_BANCA WHERE S.GENERO = 'MASCULINO' AND LOWER(S.AREA_INGRESSO) = LOWER('biologia geral') AND LOWER(S.SIGLA_CAMPUS) = LOWER('uru') AND LOWER(COALESCE(LB.NATUREZA, '')) LIKE '%curso de aperfeicoamento/especializacao%' AND LB.ANO >= CAST(strftime('%Y', 'now') AS INTEGER) - 5